arguments.argument:
if global.gamePaused=false
{
  fireFrm+=0.33
  if fireProg=0
  {
    image_alpha+=0.04
    if image_alpha>=1 {fireProg+=1}
  }
  else if fireProg=1
  {
    y-=2
    if y<=272 {fireProg+=1}
  }
  else if fireProg=2
  {
    fireTime+=1
    if fireTime>=100
    {
      image_alpha-=0.05
      if image_alpha<=0.5 {instance_destroy()}
    }
  }
}
